+	if err != nil {
+		t.Fatalf("temp file: %v", err)
+	}
+	defer func() { _ = os.Remove(tmp.Name()) }()
+	if _, err := tmp.WriteString("file-key\n"); err != nil {
+		t.Fatalf("write temp: %v", err)
