+	}
+
+	cfg.APIKeyFile = tmp.Name()
+	if err := ensureAPIKey(); err != nil {
+		t.Fatalf("ensureAPIKey error: %v", err)
+	}
+	if cfg.APIKey != "file-key" {
+		t.Fatalf("expected file key to be used, got %q", cfg.APIKey)
+	}
+}
